  2143тЖТ  /**
  2144тЖТ   * Check if a track has conflicts for the given date range.
  2145тЖТ   */
  2146тЖТ  private async checkTrackConflict(
  2147тЖТ    trackId: string,
  2148тЖТ    startDate: Date,
  2149тЖТ    durationDays: number,
  2150тЖТ    excludePmId?: string
  2151тЖТ  ): Promise<TrackConflict | null> {
  2152тЖТ    const endDate = addDays(startDate, durationDays);
  2153тЖТ    
  2154тЖТ    const conflictingPM = await this.db.query.pmSchedule.findFirst({
  2155тЖТ      where: and(
  2156тЖТ        eq(pmSchedule.assignedTrackId, trackId),
  2157тЖТ        excludePmId ? ne(pmSchedule.id, excludePmId) : undefined,
  2158тЖТ        or(
  2159тЖТ          // New PM overlaps existing PM's start
  2160тЖТ          and(
  2161тЖТ            lte(pmSchedule.targetDate, startDate),
  2162тЖТ            gte(sql`${pmSchedule.targetDate} + ${durationDays} * interval '1 day'`, startDate)
  2163тЖТ          ),
  2164тЖТ          // New PM overlaps existing PM's end
  2165тЖТ          and(
  2166тЖТ            lte(pmSchedule.targetDate, endDate),
  2167тЖТ            gte(sql`${pmSchedule.targetDate} + ${durationDays} * interval '1 day'`, startDate)
  2168тЖТ          )
  2169тЖТ        ),
  2170тЖТ        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS'])
  2171тЖТ      ),
  2172тЖТ      with: {
  2173тЖТ        pmType: true,
  2174тЖТ        train: true,
  2175тЖТ        assignedTrack: true
  2176тЖТ      }
  2177тЖТ    });
