  2181тЖТ        trackId,
  2182тЖТ        trackNumber: conflictingPM.assignedTrack.trackNumber,
  2183тЖТ        conflictingPMId: conflictingPM.id,
  2184тЖТ        conflictingPMCode: conflictingPM.pmType.pmCode,
  2185тЖТ        conflictingTrainNumber: conflictingPM.train.trainNumber,
  2186тЖТ        conflictingDateRange: {
