  2253тЖТ
  2254тЖТ## 4.5 Strategic Planner
  2255тЖТ
  2256тЖТ### 4.5.1 Purpose
  2257тЖТ
  2258тЖТGenerate and maintain the 1-10 year strategic plan using genetic algorithms, constrained by capacity envelopes from the tactical model.
  2259тЖТ
  2260тЖТ### 4.5.2 Implementation
  2261тЖТ
  2262тЖТ```typescript
  2263тЖТinterface StrategicPlannerConfig {
  2264тЖТ  horizonYears: number;          // 10
  2265тЖТ  granularity: 'MONTHLY' | 'QUARTERLY';
  2266тЖТ  populationSize: number;        // 100
  2267тЖТ  generations: number;           // 500
  2268тЖТ  mutationRate: number;          // 0.1
  2269тЖТ  eliteCount: number;            // 10
  2270тЖТ}
  2271тЖТ
  2272тЖТinterface StrategicAllocation {
  2273тЖТ  trainId: string;
  2274тЖТ  pmTypeId: string;
  2275тЖТ  targetQuarter: string;  // e.g., '2028-Q2'
  2276тЖТ  estimatedHours: number;
  2277тЖТ  estimatedCost: number;
  2278тЖТ}
  2279тЖТ
  2280тЖТclass StrategicPlanner {
  2281тЖТ  private constraintAggregation: ConstraintAggregationService;
  2282тЖТ  
  2283тЖТ  async generatePlan(
  2284тЖТ    fromBaseline: string | null
  2285тЖТ  ): Promise<StrategicPlanResult> {
  2286тЖТ    // 1. Load current fleet state
  2287тЖТ    const fleetState = await this.getFleetState();
  2288тЖТ    
  2289тЖТ    // 2. Project PM requirements for each train
  2290тЖТ    const pmRequirements = await this.projectPMRequirements(
  2291тЖТ      fleetState,
  2292тЖТ      this.config.horizonYears
  2293тЖТ    );
  2294тЖТ    
  2295тЖТ    // 3. Generate constraint envelopes for each quarter
  2296тЖТ    const envelopes = await this.generateEnvelopes();
  2297тЖТ    
  2298тЖТ    // 4. Run genetic algorithm
  2299тЖТ    const bestPlan = await this.runGeneticAlgorithm(
  2300тЖТ      pmRequirements,
  2301тЖТ      envelopes
  2302тЖТ    );
  2303тЖТ    
  2304тЖТ    // 5. Validate against constraint envelopes
  2305тЖТ    const validation = await this.validatePlan(bestPlan, envelopes);
  2306тЖТ    
  2307тЖТ    if (!validation.valid) {
  2308тЖТ      // Attempt repair
  2309тЖТ      const repairedPlan = await this.repairPlan(bestPlan, validation);
  2310тЖТ      return {
  2311тЖТ        plan: repairedPlan,
  2312тЖТ        validation: await this.validatePlan(repairedPlan, envelopes),
  2313тЖТ        metrics: this.calculateMetrics(repairedPlan)
  2314тЖТ      };
  2315тЖТ    }
  2316тЖТ    
  2317тЖТ    return {
  2318тЖТ      plan: bestPlan,
  2319тЖТ      validation,
  2320тЖТ      metrics: this.calculateMetrics(bestPlan)
  2321тЖТ    };
  2322тЖТ  }
  2323тЖТ  
  2324тЖТ  /**
  2325тЖТ   * Project PM requirements for all trains over the planning horizon.
  2326тЖТ   * 
  2327тЖТ   * CRITICAL: This implementation correctly handles:
  2328тЖТ   * 1. PM hierarchy (C4 satisfies C1/C2/C3 - resets their counters)
  2329тЖТ   * 2. Dual triggers (mileage OR time, whichever comes first)
  2330тЖТ   * 3. Recent velocity calculation for accurate projections
  2331тЖТ   * 4. Cascading projections (each PM feeds into next cycle)
  2332тЖТ   */
  2333тЖТ  private async projectPMRequirements(
  2334тЖТ    fleetState: FleetState,
  2335тЖТ    horizonYears: number
  2336тЖТ  ): Promise<PMRequirement[]> {
  2337тЖТ    const requirements: PMRequirement[] = [];
  2338тЖТ    const horizonEnd = addYears(new Date(), horizonYears);
  2339тЖТ    
  2340тЖТ    for (const train of fleetState.trains) {
  2341тЖТ      const trainRules = await this.getPMRulesForFleet(train.fleetId);
  2342тЖТ      const trainHistory = await this.getPMHistoryForTrain(train.id);
  2343тЖТ      
  2344тЖТ      // Calculate daily utilization for this train
  2345тЖТ      const dailyKm = this.calculateDailyUtilization(train, trainHistory);
  2346тЖТ      
  2347тЖТ      // Project all PM types for this train
  2348тЖТ      const trainProjections = await this.projectTrainPMs(
  2349тЖТ        train,
  2350тЖТ        trainRules,
  2351тЖТ        trainHistory,
  2352тЖТ        horizonEnd,
  2353тЖТ        dailyKm
  2354тЖТ      );
  2355тЖТ      
  2356тЖТ      requirements.push(...trainProjections);
  2357тЖТ    }
  2358тЖТ    
  2359тЖТ    return requirements;
  2360тЖТ  }
  2361тЖТ  
  2362тЖТ  /**
  2363тЖТ   * Project all PM events for a single train over the horizon.
  2364тЖТ   */
  2365тЖТ  private async projectTrainPMs(
  2366тЖТ    train: Train,
  2367тЖТ    pmRules: PMType[],
  2368тЖТ    pmHistory: PMHistory[],
  2369тЖТ    horizonEnd: Date,
  2370тЖТ    dailyKm: number
  2371тЖТ  ): Promise<PMRequirement[]> {
  2372тЖТ    const projections: PMRequirement[] = [];
  2373тЖТ    
  2374тЖТ    // Create working state (mutable copy of history + projections)
  2375тЖТ    let workingHistory = [...pmHistory];
  2376тЖТ    let currentMileage = train.currentMileageKm;
  2377тЖТ    let currentDate = new Date();
  2378тЖТ    
  2379тЖТ    // Project until we exceed horizon
  2380тЖТ    while (currentDate < horizonEnd) {
  2381тЖТ      // Find next PM due across all PM types
  2382тЖТ      let nextPM: { 
  2383тЖТ        rule: PMType; 
  2384тЖТ        date: Date; 
  2385тЖТ        mileage: number; 
  2386тЖТ        trigger: 'MILEAGE' | 'TIME' 
  2387тЖТ      } | null = null;
  2388тЖТ      
  2389тЖТ      for (const rule of pmRules) {
  2390тЖТ        const projection = this.calculateNextPMDue(
  2391тЖТ          train,
  2392тЖТ          rule,
  2393тЖТ          pmRules,
  2394тЖТ          workingHistory,
  2395тЖТ          currentMileage,
  2396тЖТ          currentDate,
  2397тЖТ          dailyKm
  2398тЖТ        );
  2399тЖТ        
  2400тЖТ        if (!nextPM || projection.date < nextPM.date) {
  2401тЖТ          nextPM = {
  2402тЖТ            rule,
  2403тЖТ            date: projection.date,
  2404тЖТ            mileage: projection.mileage,
  2405тЖТ            trigger: projection.trigger
  2406тЖТ          };
  2407тЖТ        }
  2408тЖТ      }
  2409тЖТ      
  2410тЖТ      if (!nextPM || nextPM.date > horizonEnd) break;
  2411тЖТ      
  2412тЖТ      // Create requirement
  2413тЖТ      const requirement: PMRequirement = {
  2414тЖТ        id: generateUUID(),
  2415тЖТ        trainId: train.id,
  2416тЖТ        trainNumber: train.trainNumber,
  2417тЖТ        pmTypeId: nextPM.rule.id,
  2418тЖТ        pmCode: nextPM.rule.pmCode,
  2419тЖТ        projectedDate: nextPM.date,
  2420тЖТ        projectedMileageKm: nextPM.mileage,
  2421тЖТ        triggerType: nextPM.trigger,
  2422тЖТ        confidence: workingHistory.length > 0 ? 'HISTORICAL' : 'ESTIMATED',
  2423тЖТ        estimatedHours: nextPM.rule.estimatedHours,
  2424тЖТ        trackType: nextPM.rule.trackType,
  2425тЖТ        durationDays: nextPM.rule.minTrackDays,
  2426тЖТ        // Compliance window (├ГтАЪ├В┬▒10% of interval by default)
  2427тЖТ        constraintStart: addDays(nextPM.date, -Math.round(nextPM.rule.intervalKm * 0.1 / dailyKm)),
  2428тЖТ        constraintEnd: addDays(nextPM.date, Math.round(nextPM.rule.intervalKm * 0.1 / dailyKm))
  2429тЖТ      };
  2430тЖТ      
  2431тЖТ      projections.push(requirement);
  2432тЖТ      
  2433тЖТ      // Add to working history for cascading projection
  2434тЖТ      workingHistory.push({
  2435тЖТ        id: requirement.id,
  2436тЖТ        trainId: train.id,
  2437тЖТ        pmTypeId: nextPM.rule.id,
  2438тЖТ        pmCode: nextPM.rule.pmCode,
  2439тЖТ        completionDate: nextPM.date,
  2440тЖТ        mileageAtCompletion: nextPM.mileage
  2441тЖТ      });
  2442тЖТ      
  2443тЖТ      // Advance state past this PM
  2444тЖТ      currentDate = addDays(nextPM.date, nextPM.rule.minTrackDays);
  2445тЖТ      currentMileage = nextPM.mileage + (nextPM.rule.minTrackDays * dailyKm * 0.1);
  2446тЖТ    }
  2447тЖТ    
  2448тЖТ    return projections;
  2449тЖТ  }
  2450тЖТ  
  2451тЖТ  /**
  2452тЖТ   * Calculate when the next instance of a specific PM type is due.
  2453тЖТ   * 
  2454тЖТ   * CRITICAL: Accounts for PM hierarchy - a C4 satisfies C1/C2/C3 requirements,
  2455тЖТ   * so the mileage counter resets from the C4 completion point.
  2456тЖТ   * 
  2457тЖТ   * CRITICAL: Handles "Cold Start" case where train has no PM history.
  2458тЖТ   * Without this fix, trains with high mileage and no history would show
  2459тЖТ   * ALL PMs as overdue immediately.
  2460тЖТ   */
  2461тЖТ  private calculateNextPMDue(
  2462тЖТ    train: Train,
  2463тЖТ    targetRule: PMType,
  2464тЖТ    allRules: PMType[],
  2465тЖТ    history: PMHistory[],
  2466тЖТ    currentMileage: number,
  2467тЖТ    currentDate: Date,
  2468тЖТ    dailyKm: number
  2469тЖТ  ): { date: Date; mileage: number; trigger: 'MILEAGE' | 'TIME' } {
  2470тЖТ    
  2471тЖТ    // 1. Find all PM types that SATISFY the target PM
  2472тЖТ    // (the target itself + any higher-level PM that includes target in satisfiesCodes)
  2473тЖТ    const satisfyingCodes = this.getSatisfyingCodes(targetRule.pmCode, allRules);
  2474тЖТ    
  2475тЖТ    // 2. Find the most recent PM that satisfies this requirement
  2476тЖТ    const lastSatisfying = history
  2477тЖТ      .filter(h => satisfyingCodes.includes(h.pmCode))
  2478тЖТ      .sort((a, b) => b.mileageAtCompletion - a.mileageAtCompletion)[0];
  2479тЖТ    
  2480тЖТ    // 3. Handle "Cold Start" - no PM history exists
  2481тЖТ    //    Assume train has been maintained on schedule since commissioning.
  2482тЖТ    //    Calculate which cycle we're currently in and when it started.
  2483тЖТ    let lastMileage: number;
  2484тЖТ    let lastDate: Date;
  2485тЖТ    
  2486тЖТ    if (lastSatisfying) {
  2487тЖТ      // Normal case: use actual history
  2488тЖТ      lastMileage = lastSatisfying.mileageAtCompletion;
  2489тЖТ      lastDate = new Date(lastSatisfying.completionDate);
  2490тЖТ    } else {
  2491тЖТ      // COLD START FIX: Create "virtual" last PM
  2492тЖТ      // Calculate how many complete cycles since commissioning
  2493тЖТ      const cyclesCompleted = Math.floor(currentMileage / targetRule.intervalKm);
  2494тЖТ      
  2495тЖТ      if (cyclesCompleted > 0) {
  2496тЖТ        // Assume last PM occurred at start of current cycle
  2497тЖТ        lastMileage = cyclesCompleted * targetRule.intervalKm;
  2498тЖТ        // Estimate when that mileage was reached
  2499тЖТ        const daysAgo = (currentMileage - lastMileage) / dailyKm;
  2500тЖТ        lastDate = addDays(currentDate, -daysAgo);
  2501тЖТ      } else {
  2502тЖТ        // Train hasn't completed first cycle yet - use commissioning as baseline
  2503тЖТ        lastMileage = 0;
  2504тЖТ        lastDate = train.commissioningDate;
  2505тЖТ      }
  2506тЖТ    }
  2507тЖТ    
  2508тЖТ    // 4. Calculate mileage-based due date
  2509тЖТ    const kmSinceLast = currentMileage - lastMileage;
  2510тЖТ    const kmRemaining = Math.max(0, targetRule.intervalKm - kmSinceLast);
  2511тЖТ    const daysUntilMileageDue = kmRemaining / dailyKm;
  2512тЖТ    const dateByMileage = addDays(currentDate, daysUntilMileageDue);
  2513тЖТ    const mileageAtDue = currentMileage + kmRemaining;
  2514тЖТ    
  2515тЖТ    // 5. Calculate time-based due date (if interval defined)
  2516тЖТ    let dateByTime: Date | null = null;
  2517тЖТ    if (targetRule.intervalMonths) {
  2518тЖТ      dateByTime = addMonths(lastDate, targetRule.intervalMonths);
  2519тЖТ    }
  2520тЖТ    
  2521тЖТ    // 6. Return whichever comes first (dual trigger)
  2522тЖТ    if (dateByTime && dateByTime < dateByMileage) {
  2523тЖТ      const daysUntilTime = differenceInDays(dateByTime, currentDate);
  2524тЖТ      const mileageAtTime = currentMileage + (Math.max(0, daysUntilTime) * dailyKm);
  2525тЖТ      return { date: dateByTime, mileage: mileageAtTime, trigger: 'TIME' };
  2526тЖТ    } else {
  2527тЖТ      return { date: dateByMileage, mileage: mileageAtDue, trigger: 'MILEAGE' };
  2528тЖТ    }
  2529тЖТ  }
  2530тЖТ  
  2531тЖТ  /**
  2532тЖТ   * Find all PM codes that satisfy a target PM code.
  2533тЖТ   * Returns the target itself plus any higher-level PMs that include it in satisfiesCodes.
  2534тЖТ   * 
  2535тЖТ   * Example: For C2, returns ['C2', 'C3', 'C4', 'OH'] because C3/C4/OH all satisfy C2.
  2536тЖТ   */
  2537тЖТ  private getSatisfyingCodes(targetCode: string, allRules: PMType[]): string[] {
  2538тЖТ    const result = [targetCode];
  2539тЖТ    
  2540тЖТ    for (const rule of allRules) {
  2541тЖТ      if (rule.satisfiesCodes?.includes(targetCode)) {
  2542тЖТ        result.push(rule.pmCode);
  2543тЖТ      }
  2544тЖТ    }
  2545тЖТ    
  2546тЖТ    return result;
  2547тЖТ  }
  2548тЖТ  
  2549тЖТ  /**
  2550тЖТ   * Calculate daily mileage rate for a train.
  2551тЖТ   * Uses recent velocity (between last 2 PMs) if available for accuracy,
  2552тЖТ   * falls back to lifetime average from commissioning date.
  2553тЖТ   */
  2554тЖТ  private calculateDailyUtilization(train: Train, history: PMHistory[]): number {
  2555тЖТ    // Filter valid entries (positive mileage)
  2556тЖТ    const validHistory = history
  2557тЖТ      .filter(h => h.mileageAtCompletion > 0)
  2558тЖТ      .sort((a, b) => new Date(b.completionDate).getTime() - new Date(a.completionDate).getTime());
  2559тЖТ    
  2560тЖТ    // Try: Recent velocity between last 2 PMs (most accurate)
  2561тЖТ    if (validHistory.length >= 2) {
  2562тЖТ      const recent = validHistory[0];
  2563тЖТ      const previous = validHistory[1];
  2564тЖТ      const daysBetween = differenceInDays(
  2565тЖТ        new Date(recent.completionDate),
  2566тЖТ        new Date(previous.completionDate)
  2567тЖТ      );
  2568тЖТ      const kmBetween = recent.mileageAtCompletion - previous.mileageAtCompletion;
  2569тЖТ      
  2570тЖТ      // Sanity checks: at least 14 days apart, positive mileage, reasonable rate
  2571тЖТ      if (daysBetween >= 14 && kmBetween > 0) {
  2572тЖТ        const rate = kmBetween / daysBetween;
  2573тЖТ        // Typical metro range: 50-500 km/day
  2574тЖТ        if (rate > 50 && rate < 500) {
  2575тЖТ          return rate;
  2576тЖТ        }
  2577тЖТ      }
  2578тЖТ    }
  2579тЖТ    
  2580тЖТ    // Fallback: Lifetime average from commissioning
  2581тЖТ    const daysSinceCommission = differenceInDays(new Date(), train.commissioningDate);
  2582тЖТ    if (daysSinceCommission > 0 && train.currentMileageKm > 0) {
  2583тЖТ      return train.currentMileageKm / daysSinceCommission;
  2584тЖТ    }
  2585тЖТ    
  2586тЖТ    // Last resort: Fleet typical value
  2587тЖТ    return 150;  // Conservative metro average
  2588тЖТ  }
  2589тЖТ  
  2590тЖТ  private async runGeneticAlgorithm(
  2591тЖТ    requirements: PMRequirement[],
  2592тЖТ    envelopes: ConstraintEnvelope[]
  2593тЖТ  ): Promise<StrategicAllocation[]> {
  2594тЖТ    // Initialize population
  2595тЖТ    let population = this.initializePopulation(requirements, envelopes);
  2596тЖТ    
  2597тЖТ    for (let gen = 0; gen < this.config.generations; gen++) {
  2598тЖТ      // Evaluate fitness
  2599тЖТ      const fitness = population.map(individual => 
  2600тЖТ        this.evaluateFitness(individual, envelopes)
  2601тЖТ      );
  2602тЖТ      
  2603тЖТ      // Selection
  2604тЖТ      const selected = this.tournamentSelection(population, fitness);
  2605тЖТ      
  2606тЖТ      // Crossover
  2607тЖТ      const offspring = this.crossover(selected);
  2608тЖТ      
  2609тЖТ      // Mutation
  2610тЖТ      const mutated = this.mutate(offspring, envelopes);
  2611тЖТ      
  2612тЖТ      // Elitism
  2613тЖТ      const elite = this.selectElite(population, fitness);
  2614тЖТ      
  2615тЖТ      // New population
  2616тЖТ      population = [...elite, ...mutated];
  2617тЖТ      
  2618тЖТ      // Progress
  2619тЖТ      if (gen % 50 === 0) {
  2620тЖТ        const bestFitness = Math.max(...fitness);
  2621тЖТ        this.emitProgress(gen, this.config.generations, bestFitness);
  2622тЖТ      }
  2623тЖТ    }
  2624тЖТ    
  2625тЖТ    // Return best individual
  2626тЖТ    const finalFitness = population.map(i => 
  2627тЖТ      this.evaluateFitness(i, envelopes)
  2628тЖТ    );
  2629тЖТ    const bestIndex = finalFitness.indexOf(Math.max(...finalFitness));
  2630тЖТ    
  2631тЖТ    return population[bestIndex];
  2632тЖТ  }
  2633тЖТ  
  2634тЖТ  private evaluateFitness(
  2635тЖТ    individual: StrategicAllocation[],
  2636тЖТ    envelopes: ConstraintEnvelope[]
  2637тЖТ  ): number {
  2638тЖТ    let fitness = 1000;  // Start with base score
  2639тЖТ    
  2640тЖТ    // Penalty for constraint envelope violations
  2641тЖТ    for (const envelope of envelopes) {
  2642тЖТ      const quarterAllocations = individual.filter(
  2643тЖТ        a => a.targetQuarter === this.quarterKey(envelope.period)
  2644тЖТ      );
  2645тЖТ      
  2646тЖТ      // Track capacity check
  2647тЖТ      const trackHours = this.sumByTrackType(quarterAllocations);
  2648тЖТ      for (const [trackType, hours] of Object.entries(trackHours)) {
  2649тЖТ        const available = envelope.track_capacity.find(
  2650тЖТ          t => t.track_type === trackType
  2651тЖТ        )?.available_slot_days || 0;
  2652тЖТ        
  2653тЖТ        if (hours > available * 8) {  // 8 hours per slot-day
  2654тЖТ          fitness -= (hours - available * 8) * 10;  // Heavy penalty
  2655тЖТ        }
  2656тЖТ      }
  2657тЖТ      
  2658тЖТ      // Labor capacity check
  2659тЖТ      const totalHours = quarterAllocations.reduce(
  2660тЖТ        (sum, a) => sum + a.estimatedHours, 0
  2661тЖТ      );
  2662тЖТ      const availableLabor = envelope.labor_capacity.reduce(
  2663тЖТ        (sum, l) => sum + l.available_hours, 0
  2664тЖТ      );
  2665тЖТ      
  2666тЖТ      if (totalHours > availableLabor) {
  2667тЖТ        fitness -= (totalHours - availableLabor) * 5;
  2668тЖТ      }
  2669тЖТ      
  2670тЖТ      // Material capacity check (soft)
  2671тЖТ      // ... similar logic
  2672тЖТ    }
  2673тЖТ    
  2674тЖТ    // Bonus for workload leveling
  2675тЖТ    const quarterHours = this.groupByQuarter(individual);
  2676тЖТ    const variance = this.calculateVariance(Object.values(quarterHours));
  2677тЖТ    fitness -= variance * 0.1;  // Prefer even distribution
  2678тЖТ    
  2679тЖТ    // Bonus for respecting compliance windows
  2680тЖТ    for (const allocation of individual) {
  2681тЖТ      const compliance = this.checkComplianceWindow(allocation);
  2682тЖТ      if (compliance.inWindow) {
  2683тЖТ        fitness += 5;
  2684тЖТ      } else if (compliance.early) {
  2685тЖТ        fitness -= 2;  // Small penalty for early
  2686тЖТ      } else {
  2687тЖТ        fitness -= 20;  // Large penalty for late
  2688тЖТ      }
  2689тЖТ    }
  2690тЖТ    
  2691тЖТ    return Math.max(0, fitness);
  2692тЖТ  }
  2693тЖТ  
  2694тЖТ  private async generateEnvelopes(): Promise<ConstraintEnvelope[]> {
  2695тЖТ    const envelopes: ConstraintEnvelope[] = [];
  2696тЖТ    const startDate = new Date();
  2697тЖТ    
  2698тЖТ    for (let q = 0; q < this.config.horizonYears * 4; q++) {
  2699тЖТ      const quarterStart = addMonths(startDate, q * 3);
  2700тЖТ      const quarterEnd = addMonths(quarterStart, 3);
  2701тЖТ      
  2702тЖТ      const envelope = await this.constraintAggregation.generateEnvelope(
  2703тЖТ        quarterStart,
  2704тЖТ        quarterEnd,
  2705тЖТ        await this.getAllDepotIds()
  2706тЖТ      );
  2707тЖТ      
  2708тЖТ      envelopes.push(envelope);
  2709тЖТ    }
  2710тЖТ    
  2711тЖТ    return envelopes;
  2712тЖТ  }
  2713тЖТ}
  2714тЖТ```
