  2717тЖТ
  2718тЖТ## 4.6 Man-hour Leveling Engine
  2719тЖТ
  2720тЖТ### 4.6.1 Purpose
  2721тЖТ
  2722тЖТProject workforce requirements and generate adjustment recommendations to balance workload across time periods.
  2723тЖТ
  2724тЖТ### 4.6.2 Implementation
  2725тЖТ
  2726тЖТ```typescript
  2727тЖТinterface LevelingStrategy {
  2728тЖТ  type: 'DEFER_PM' | 'ADVANCE_PM' | 'ADD_OVERTIME' | 'CROSS_DEPOT' | 'ADD_CONTRACTOR';
  2729тЖТ  priority: number;
  2730тЖТ  maxHoursPerWeek: number;
  2731тЖТ  costMultiplier: number;
  2732тЖТ  riskLevel: 'NONE' | 'LOW' | 'MEDIUM' | 'HIGH';
  2733тЖТ}
  2734тЖТ
  2735тЖТconst LEVELING_STRATEGIES: LevelingStrategy[] = [
  2736тЖТ  { type: 'ADVANCE_PM', priority: 1, maxHoursPerWeek: 40, costMultiplier: 1.1, riskLevel: 'LOW' },
  2737тЖТ  { type: 'DEFER_PM', priority: 2, maxHoursPerWeek: 40, costMultiplier: 1.05, riskLevel: 'LOW' },
  2738тЖТ  { type: 'ADD_OVERTIME', priority: 3, maxHoursPerWeek: 80, costMultiplier: 1.5, riskLevel: 'NONE' },
  2739тЖТ  { type: 'CROSS_DEPOT', priority: 4, maxHoursPerWeek: 60, costMultiplier: 1.3, riskLevel: 'MEDIUM' },
  2740тЖТ  { type: 'ADD_CONTRACTOR', priority: 5, maxHoursPerWeek: 100, costMultiplier: 2.0, riskLevel: 'MEDIUM' },
  2741тЖТ];
  2742тЖТ
  2743тЖТclass ManHourLevelingEngine {
  2744тЖТ  private readonly TARGET_UTILIZATION = 0.85;
  2745тЖТ  private readonly MIN_UTILIZATION = 0.70;
  2746тЖТ  private readonly MAX_UTILIZATION = 1.00;
  2747тЖТ  
  2748тЖТ  async generateProjections(
  2749тЖТ    horizonWeeks: number = 12,
  2750тЖТ    depotIds?: string[]
  2751тЖТ  ): Promise<LevelingResult> {
  2752тЖТ    const runId = crypto.randomUUID();
  2753тЖТ    
  2754тЖТ    // 1. Calculate raw projections
  2755тЖТ    const rawProjections = await this.calculateRawProjections(
  2756тЖТ      horizonWeeks,
  2757тЖТ      depotIds
  2758тЖТ    );
  2759тЖТ    
  2760тЖТ    // 2. Identify imbalances
  2761тЖТ    const imbalances = this.identifyImbalances(rawProjections);
  2762тЖТ    
  2763тЖТ    // 3. Generate adjustments using multiple strategies
  2764тЖТ    const adjustments = await this.generateAdjustments(
  2765тЖТ      rawProjections,
  2766тЖТ      imbalances
  2767тЖТ    );
  2768тЖТ    
  2769тЖТ    // 4. Apply adjustments to get leveled projections
  2770тЖТ    const leveledProjections = this.applyAdjustments(
  2771тЖТ      rawProjections,
  2772тЖТ      adjustments
  2773тЖТ    );
  2774тЖТ    
  2775тЖТ    // 5. Calculate metrics
  2776тЖТ    const originalMetrics = this.calculateMetrics(rawProjections);
  2777тЖТ    const leveledMetrics = this.calculateMetrics(leveledProjections);
  2778тЖТ    
  2779тЖТ    // 6. Persist
  2780тЖТ    await this.persistProjections(runId, rawProjections, leveledProjections, adjustments);
  2781тЖТ    
  2782тЖТ    // 7. Broadcast update
  2783тЖТ    await this.websocketHub.broadcast('manhour:updated', {
  2784тЖТ      runId,
  2785тЖТ      summary: { originalMetrics, leveledMetrics }
  2786тЖТ    });
  2787тЖТ    
  2788тЖТ    return {
  2789тЖТ      projectionRunId: runId,
  2790тЖТ      generatedAt: new Date(),
  2791тЖТ      horizonWeeks,
  2792тЖТ      original: { projections: rawProjections, metrics: originalMetrics },
  2793тЖТ      leveled: { projections: leveledProjections, metrics: leveledMetrics },
  2794тЖТ      adjustments,
  2795тЖТ      improvement: {
  2796тЖТ        utilizationDelta: leveledMetrics.avgUtilization - originalMetrics.avgUtilization,
  2797тЖТ        overloadedWeeksReduced: originalMetrics.overloadedWeeks - leveledMetrics.overloadedWeeks,
  2798тЖТ        totalCostImpact: adjustments.reduce((sum, a) => sum + a.costImpact, 0)
  2799тЖТ      }
  2800тЖТ    };
  2801тЖТ  }
  2802тЖТ  
  2803тЖТ  private async generateAdjustments(
  2804тЖТ    projections: ManHourProjection[],
  2805тЖТ    imbalances: Imbalance[]
  2806тЖТ  ): Promise<ManHourAdjustment[]> {
  2807тЖТ    const adjustments: ManHourAdjustment[] = [];
  2808тЖТ    const byDepot = this.groupByDepot(projections);
  2809тЖТ    
  2810тЖТ    for (const [depotId, depotProjections] of byDepot) {
  2811тЖТ      const overloaded = depotProjections.filter(p => p.isOverloaded);
  2812тЖТ      const underutilized = depotProjections.filter(p => p.isUnderutilized);
  2813тЖТ      
  2814тЖТ      for (const overWeek of overloaded) {
  2815тЖТ        let remainingExcess = overWeek.required.total - overWeek.available.total;
  2816тЖТ        
  2817тЖТ        // Try each strategy in priority order
  2818тЖТ        for (const strategy of LEVELING_STRATEGIES) {
  2819тЖТ          if (remainingExcess <= 0) break;
  2820тЖТ          
  2821тЖТ          const adjustment = await this.tryStrategy(
  2822тЖТ            strategy,
  2823тЖТ            overWeek,
  2824тЖТ            underutilized,
  2825тЖТ            depotProjections,
  2826тЖТ            remainingExcess
  2827тЖТ          );
  2828тЖТ          
  2829тЖТ          if (adjustment) {
  2830тЖТ            adjustments.push(adjustment);
  2831тЖТ            remainingExcess -= adjustment.hoursAdjusted;
  2832тЖТ            
  2833тЖТ            // Update underutilized list if we used capacity
  2834тЖТ            if (adjustment.type === 'ADVANCE_PM' || adjustment.type === 'DEFER_PM') {
  2835тЖТ              this.updateUnderutilizedCapacity(underutilized, adjustment);
  2836тЖТ            }
  2837тЖТ          }
  2838тЖТ        }
  2839тЖТ        
  2840тЖТ        // If still overloaded, flag for manual review
  2841тЖТ        if (remainingExcess > 0) {
  2842тЖТ          adjustments.push({
  2843тЖТ            type: 'MANUAL_REVIEW',
  2844тЖТ            sourcePeriod: { start: overWeek.week, end: addDays(overWeek.week, 7) },
  2845тЖТ            hoursAdjusted: 0,
  2846тЖТ            affectedPMs: [],
  2847тЖТ            costImpact: 0,
  2848тЖТ            riskLevel: 'HIGH',
  2849тЖТ            reason: `Unable to resolve ${remainingExcess.toFixed(0)}h overload - requires manual intervention`
  2850тЖТ          });
  2851тЖТ        }
  2852тЖТ      }
  2853тЖТ    }
  2854тЖТ    
  2855тЖТ    return adjustments;
  2856тЖТ  }
  2857тЖТ  
  2858тЖТ  private async tryStrategy(
  2859тЖТ    strategy: LevelingStrategy,
  2860тЖТ    overloadedWeek: ManHourProjection,
  2861тЖТ    underutilizedWeeks: ManHourProjection[],
  2862тЖТ    allProjections: ManHourProjection[],
  2863тЖТ    excessHours: number
  2864тЖТ  ): Promise<ManHourAdjustment | null> {
  2865тЖТ    const maxHours = Math.min(strategy.maxHoursPerWeek, excessHours);
  2866тЖТ    
  2867тЖТ    switch (strategy.type) {
  2868тЖТ      case 'ADVANCE_PM':
  2869тЖТ      case 'DEFER_PM': {
  2870тЖТ        // Find candidate weeks
  2871тЖТ        const candidates = underutilizedWeeks
  2872тЖТ          .filter(w => {
  2873тЖТ            const weekDiff = differenceInWeeks(w.week, overloadedWeek.week);
  2874тЖТ            const direction = strategy.type === 'ADVANCE_PM' ? -1 : 1;
  2875тЖТ            return weekDiff * direction > 0 && Math.abs(weekDiff) <= 4;
  2876тЖТ          })
  2877тЖТ          .sort((a, b) => 
  2878тЖТ            Math.abs(differenceInWeeks(a.week, overloadedWeek.week)) -
  2879тЖТ            Math.abs(differenceInWeeks(b.week, overloadedWeek.week))
  2880тЖТ          );
  2881тЖТ        
  2882тЖТ        for (const candidate of candidates) {
  2883тЖТ          const availableCapacity = candidate.available.total - candidate.required.total;
  2884тЖТ          const shiftHours = Math.min(maxHours, availableCapacity * 0.8);
  2885тЖТ          
  2886тЖТ          if (shiftHours >= 8) {  // Minimum meaningful shift
  2887тЖТ            // Find PMs that can be shifted
  2888тЖТ            const shiftablePMs = await this.findShiftablePMs(
  2889тЖТ              overloadedWeek,
  2890тЖТ              candidate,
  2891тЖТ              shiftHours,
  2892тЖТ              strategy.type
  2893тЖТ            );
  2894тЖТ            
  2895тЖТ            if (shiftablePMs.length > 0) {
  2896тЖТ              const actualHours = shiftablePMs.reduce(
  2897тЖТ                (sum, pm) => sum + pm.estimatedHours, 0
  2898тЖТ              );
  2899тЖТ              
  2900тЖТ              return {
  2901тЖТ                type: strategy.type,
  2902тЖТ                sourcePeriod: { 
  2903тЖТ                  start: overloadedWeek.week, 
  2904тЖТ                  end: addDays(overloadedWeek.week, 7) 
  2905тЖТ                },
  2906тЖТ                targetPeriod: { 
  2907тЖТ                  start: candidate.week, 
  2908тЖТ                  end: addDays(candidate.week, 7) 
  2909тЖТ                },
  2910тЖТ                hoursAdjusted: actualHours,
  2911тЖТ                affectedPMs: shiftablePMs.map(pm => pm.id),
  2912тЖТ                costImpact: actualHours * this.getBaseRate() * (strategy.costMultiplier - 1),
  2913тЖТ                riskLevel: strategy.riskLevel,
  2914тЖТ                reason: `${strategy.type === 'DEFER_PM' ? 'Defer' : 'Advance'} ${actualHours.toFixed(0)}h from Week ${format(overloadedWeek.week, 'ww')} to Week ${format(candidate.week, 'ww')}`
  2915тЖТ              };
  2916тЖТ            }
  2917тЖТ          }
  2918тЖТ        }
  2919тЖТ        return null;
  2920тЖТ      }
  2921тЖТ      
  2922тЖТ      case 'ADD_OVERTIME': {
  2923тЖТ        const availableOvertime = overloadedWeek.available.overtime;
  2924тЖТ        const overtimeHours = Math.min(maxHours, availableOvertime);
  2925тЖТ        
  2926тЖТ        if (overtimeHours >= 4) {
  2927тЖТ          return {
  2928тЖТ            type: 'ADD_OVERTIME',
  2929тЖТ            sourcePeriod: { 
  2930тЖТ              start: overloadedWeek.week, 
  2931тЖТ              end: addDays(overloadedWeek.week, 7) 
  2932тЖТ            },
  2933тЖТ            targetPeriod: { 
  2934тЖТ              start: overloadedWeek.week, 
  2935тЖТ              end: addDays(overloadedWeek.week, 7) 
  2936тЖТ            },
  2937тЖТ            hoursAdjusted: overtimeHours,
  2938тЖТ            affectedPMs: [],
  2939тЖТ            costImpact: overtimeHours * this.getBaseRate() * (strategy.costMultiplier - 1),
  2940тЖТ            riskLevel: strategy.riskLevel,
  2941тЖТ            reason: `Add ${overtimeHours.toFixed(0)}h overtime in Week ${format(overloadedWeek.week, 'ww')}`
  2942тЖТ          };
  2943тЖТ        }
  2944тЖТ        return null;
  2945тЖТ      }
  2946тЖТ      
  2947тЖТ      case 'CROSS_DEPOT': {
  2948тЖТ        // Find other depots with capacity
  2949тЖТ        const otherDepots = await this.findDepotsWithCapacity(
  2950тЖТ          overloadedWeek.week,
  2951тЖТ          maxHours
  2952тЖТ        );
  2953тЖТ        
  2954тЖТ        if (otherDepots.length > 0) {
  2955тЖТ          const best = otherDepots[0];
  2956тЖТ          return {
  2957тЖТ            type: 'CROSS_DEPOT',
  2958тЖТ            sourcePeriod: { 
  2959тЖТ              start: overloadedWeek.week, 
  2960тЖТ              end: addDays(overloadedWeek.week, 7) 
  2961тЖТ            },
  2962тЖТ            targetPeriod: { 
  2963тЖТ              start: overloadedWeek.week, 
  2964тЖТ              end: addDays(overloadedWeek.week, 7) 
  2965тЖТ            },
  2966тЖТ            hoursAdjusted: best.availableHours,
  2967тЖТ            affectedPMs: [],
  2968тЖТ            costImpact: best.availableHours * this.getBaseRate() * (strategy.costMultiplier - 1),
  2969тЖТ            riskLevel: strategy.riskLevel,
  2970тЖТ            reason: `Request ${best.availableHours.toFixed(0)}h support from ${best.depotName} in Week ${format(overloadedWeek.week, 'ww')}`
  2971тЖТ          };
  2972тЖТ        }
  2973тЖТ        return null;
  2974тЖТ      }
  2975тЖТ      
  2976тЖТ      case 'ADD_CONTRACTOR': {
  2977тЖТ        return {
  2978тЖТ          type: 'ADD_CONTRACTOR',
  2979тЖТ          sourcePeriod: { 
  2980тЖТ            start: overloadedWeek.week, 
  2981тЖТ            end: addDays(overloadedWeek.week, 7) 
  2982тЖТ          },
  2983тЖТ          targetPeriod: { 
  2984тЖТ            start: overloadedWeek.week, 
  2985тЖТ            end: addDays(overloadedWeek.week, 7) 
  2986тЖТ          },
  2987тЖТ          hoursAdjusted: maxHours,
  2988тЖТ          affectedPMs: [],
  2989тЖТ          costImpact: maxHours * this.getBaseRate() * (strategy.costMultiplier - 1),
  2990тЖТ          riskLevel: strategy.riskLevel,
  2991тЖТ          reason: `Engage contractor for ${maxHours.toFixed(0)}h in Week ${format(overloadedWeek.week, 'ww')}`
  2992тЖТ        };
  2993тЖТ      }
  2994тЖТ    }
  2995тЖТ    
  2996тЖТ    return null;
  2997тЖТ  }
  2998тЖТ}
  2999тЖТ```
