  3003тЖТ## 4.7 Baseline Service
  3004тЖТ
  3005тЖТ### 4.7.1 Purpose
  3006тЖТ
  3007тЖТManage published plan baselines for drift analysis and scenario comparison.
  3008тЖТ
  3009тЖТ### 4.7.2 Implementation
  3010тЖТ
  3011тЖТ```typescript
  3012тЖТclass BaselineService {
  3013тЖТ  async publishBaseline(
  3014тЖТ    name: string,
  3015тЖТ    description: string,
  3016тЖТ    userId: string
  3017тЖТ  ): Promise<PlanBaseline> {
  3018тЖТ    // 1. Validate current plan has no critical conflicts
  3019тЖТ    const validation = await this.validatePlanForPublishing();
  3020тЖТ    if (!validation.valid) {
  3021тЖТ      throw new ValidationError(
  3022тЖТ        'Cannot publish baseline with critical conflicts',
  3023тЖТ        validation.conflicts
  3024тЖТ      );
  3025тЖТ    }
  3026тЖТ    
  3027тЖТ    // 2. Generate version number
  3028тЖТ    const latestBaseline = await this.getLatestBaseline();
  3029тЖТ    const version = this.incrementVersion(latestBaseline?.version || 'v0.0');
  3030тЖТ    
  3031тЖТ    // 3. Create baseline record
  3032тЖТ    const baseline = await this.db.transaction(async (tx) => {
  3033тЖТ      // Create baseline
  3034тЖТ      const [baselineRecord] = await tx.insert(planBaselines)
  3035тЖТ        .values({
  3036тЖТ          name,
  3037тЖТ          description,
  3038тЖТ          version,
  3039тЖТ          baselineDate: new Date(),
  3040тЖТ          horizonEnd: addYears(new Date(), 10),
  3041тЖТ          status: 'PUBLISHED',
  3042тЖТ          createdBy: userId,
  3043тЖТ          publishedBy: userId,
  3044тЖТ          publishedAt: new Date(),
  3045тЖТ          fleetCount: await this.getActiveTrainCount(),
  3046тЖТ          totalPmScheduled: await this.getScheduledPMCount(),
  3047тЖТ          totalManhoursProjected: await this.getTotalProjectedHours()
  3048тЖТ        })
  3049тЖТ        .returning();
  3050тЖТ      
  3051тЖТ      // Snapshot PM schedule
  3052тЖТ      await tx.execute(sql`
  3053тЖТ        INSERT INTO baseline_pm_schedule 
  3054тЖТ          (baseline_id, train_id, pm_type_id, projected_date, projected_mileage_km, assigned_depot_id, assigned_hours)
  3055тЖТ        SELECT 
  3056тЖТ          ${baselineRecord.id},
  3057тЖТ          train_id,
  3058тЖТ          pm_type_id,
  3059тЖТ          target_date,
  3060тЖТ          target_mileage_km,
  3061тЖТ          assigned_depot_id,
  3062тЖТ          assigned_hours
  3063тЖТ        FROM pm_schedule
  3064тЖТ        WHERE scenario_id IS NULL
  3065тЖТ          AND status IN ('SCHEDULED', 'IN_PROGRESS')
  3066тЖТ          AND target_date >= CURRENT_DATE
  3067тЖТ      `);
  3068тЖТ      
  3069тЖТ      // Snapshot mileage projections
  3070тЖТ      const projections = await this.generateMileageProjections(
  3071тЖТ        baselineRecord.horizonEnd
  3072тЖТ      );
  3073тЖТ      
  3074тЖТ      for (const proj of projections) {
  3075тЖТ        await tx.insert(baselineMileageProjection)
  3076тЖТ          .values({
  3077тЖТ            baselineId: baselineRecord.id,
  3078тЖТ            trainId: proj.trainId,
  3079тЖТ            projectionDate: proj.date,
  3080тЖТ            projectedCumulativeKm: proj.projectedKm,
  3081тЖТ            dailyRateKm: proj.dailyRate
  3082тЖТ          });
  3083тЖТ      }
  3084тЖТ      
  3085тЖТ      // Supersede previous baseline
  3086тЖТ      if (latestBaseline) {
  3087тЖТ        await tx.update(planBaselines)
  3088тЖТ          .set({
  3089тЖТ            status: 'SUPERSEDED',
  3090тЖТ            supersededBy: baselineRecord.id,
  3091тЖТ            supersededAt: new Date()
  3092тЖТ          })
  3093тЖТ          .where(eq(planBaselines.id, latestBaseline.id));
  3094тЖТ      }
  3095тЖТ      
  3096тЖТ      return baselineRecord;
  3097тЖТ    });
  3098тЖТ    
  3099тЖТ    // 4. Audit log
  3100тЖТ    await this.auditLog.record({
  3101тЖТ      entityType: 'plan_baseline',
  3102тЖТ      entityId: baseline.id,
  3103тЖТ      action: 'PUBLISH',
  3104тЖТ      userId,
  3105тЖТ      newValues: { name, version, description }
  3106тЖТ    });
  3107тЖТ    
  3108тЖТ    // 5. Notify
  3109тЖТ    await this.notificationService.notify({
  3110тЖТ      type: 'BASELINE_PUBLISHED',
  3111тЖТ      title: `New baseline published: ${version}`,
  3112тЖТ      body: description,
  3113тЖТ      recipients: await this.getPlannerUserIds()
  3114тЖТ    });
  3115тЖТ    
  3116тЖТ    return baseline;
  3117тЖТ  }
  3118тЖТ  
  3119тЖТ  private async generateMileageProjections(
  3120тЖТ    horizonEnd: Date
  3121тЖТ  ): Promise<MileageProjection[]> {
  3122тЖТ    const trains = await this.db.query.trains.findMany({
  3123тЖТ      where: eq(trains.active, true)
  3124тЖТ    });
  3125тЖТ    
  3126тЖТ    const projections: MileageProjection[] = [];
  3127тЖТ    
  3128тЖТ    for (const train of trains) {
  3129тЖТ      // Calculate average daily mileage from last 30 days
  3130тЖТ      const recentMileage = await this.db.query.mileageReadings.findMany({
  3131тЖТ        where: and(
  3132тЖТ          eq(mileageReadings.trainId, train.id),
  3133тЖТ          gte(mileageReadings.readingDate, subDays(new Date(), 30)),
  3134тЖТ          eq(mileageReadings.validationStatus, 'VALID')
  3135тЖТ        )
  3136тЖТ      });
  3137тЖТ      
  3138тЖТ      const avgDailyKm = recentMileage.length > 0
  3139тЖТ        ? recentMileage.reduce((sum, r) => sum + (r.dailyKm || 0), 0) / recentMileage.length
  3140тЖТ        : 150;  // Default if no history
  3141тЖТ      
  3142тЖТ      // Project forward at monthly intervals
  3143тЖТ      let currentKm = train.currentMileageKm;
  3144тЖТ      let currentDate = new Date();
  3145тЖТ      
  3146тЖТ      while (currentDate < horizonEnd) {
  3147тЖТ        currentDate = addMonths(currentDate, 1);
  3148тЖТ        currentKm += avgDailyKm * 30;
  3149тЖТ        
  3150тЖТ        projections.push({
  3151тЖТ          trainId: train.id,
  3152тЖТ          date: currentDate,
  3153тЖТ          projectedKm: Math.round(currentKm),
  3154тЖТ          dailyRate: Math.round(avgDailyKm)
  3155тЖТ        });
  3156тЖТ      }
  3157тЖТ    }
  3158тЖТ    
  3159тЖТ    return projections;
  3160тЖТ  }
  3161тЖТ}
  3162тЖТ```
