  3166тЖТ## 4.8 Drift Monitor Service
  3167тЖТ
  3168тЖТ### 4.8.1 Purpose
  3169тЖТ
  3170тЖТCompare actual state against published baseline, calculate drift metrics, and alert when thresholds are exceeded.
  3171тЖТ
  3172тЖТ### 4.8.2 Implementation
  3173тЖТ
  3174тЖТ```typescript
  3175тЖТinterface DriftThresholds {
  3176тЖТ  mileageDriftPct: number;        // 5.0
  3177тЖТ  scheduleDriftDays: number;      // 14
  3178тЖТ  fleetDriftTrainCount: number;   // 5
  3179тЖТ}
  3180тЖТ
  3181тЖТclass DriftMonitorService {
  3182тЖТ  private readonly thresholds: DriftThresholds = {
  3183тЖТ    mileageDriftPct: 5.0,
  3184тЖТ    scheduleDriftDays: 14,
  3185тЖТ    fleetDriftTrainCount: 5
  3186тЖТ  };
  3187тЖТ  
  3188тЖТ  /**
  3189тЖТ   * Run nightly drift analysis
  3190тЖТ   */
  3191тЖТ  async runDriftAnalysis(): Promise<DriftAnalysisResult> {
  3192тЖТ    const baseline = await this.getPublishedBaseline();
  3193тЖТ    if (!baseline) {
  3194тЖТ      this.logger.info('No published baseline, skipping drift analysis');
  3195тЖТ      return { skipped: true, reason: 'No published baseline' };
  3196тЖТ    }
  3197тЖТ    
  3198тЖТ    const analysisDate = new Date();
  3199тЖТ    const trainAnalyses: TrainDriftAnalysis[] = [];
  3200тЖТ    const alerts: DriftAlert[] = [];
  3201тЖТ    
  3202тЖТ    // Analyze each train
  3203тЖТ    const trains = await this.db.query.trains.findMany({
  3204тЖТ      where: eq(trains.active, true)
  3205тЖТ    });
  3206тЖТ    
  3207тЖТ    for (const train of trains) {
  3208тЖТ      const analysis = await this.analyzeTrainDrift(train, baseline, analysisDate);
  3209тЖТ      trainAnalyses.push(analysis);
  3210тЖТ      
  3211тЖТ      // Check thresholds
  3212тЖТ      if (analysis.requiresReplan) {
  3213тЖТ        alerts.push({
  3214тЖТ          trainId: train.id,
  3215тЖТ          trainNumber: train.trainNumber,
  3216тЖТ          severity: 'HIGH',
  3217тЖТ          type: 'REPLAN_REQUIRED',
  3218тЖТ          message: analysis.replanReason,
  3219тЖТ          metrics: {
  3220тЖТ            mileageDriftPct: analysis.mileageDriftPct,
  3221тЖТ            avgPmDriftDays: analysis.avgPmDriftDays
  3222тЖТ          }
  3223тЖТ        });
  3224тЖТ      } else if (Math.abs(analysis.mileageDriftPct) > this.thresholds.mileageDriftPct * 0.7) {
  3225тЖТ        alerts.push({
  3226тЖТ          trainId: train.id,
  3227тЖТ          trainNumber: train.trainNumber,
  3228тЖТ          severity: 'MEDIUM',
  3229тЖТ          type: 'APPROACHING_THRESHOLD',
  3230тЖТ          message: `Mileage drift at ${analysis.mileageDriftPct.toFixed(1)}% (threshold: ${this.thresholds.mileageDriftPct}%)`,
  3231тЖТ          metrics: {
  3232тЖТ            mileageDriftPct: analysis.mileageDriftPct
  3233тЖТ          }
  3234тЖТ        });
  3235тЖТ      }
  3236тЖТ      
  3237тЖТ      // Persist analysis
  3238тЖТ      await this.persistDriftAnalysis(analysis, baseline.id, analysisDate);
  3239тЖТ    }
  3240тЖТ    
  3241тЖТ    // Fleet-level analysis
  3242тЖТ    const trainsRequiringReplan = trainAnalyses.filter(a => a.requiresReplan).length;
  3243тЖТ    
  3244тЖТ    if (trainsRequiringReplan >= this.thresholds.fleetDriftTrainCount) {
  3245тЖТ      alerts.push({
  3246тЖТ        severity: 'CRITICAL',
  3247тЖТ        type: 'FLEET_REPLAN_RECOMMENDED',
  3248тЖТ        message: `${trainsRequiringReplan} trains require replanning - consider strategic replan`,
  3249тЖТ        metrics: {
  3250тЖТ          affectedTrains: trainsRequiringReplan
  3251тЖТ        }
  3252тЖТ      });
  3253тЖТ    }
  3254тЖТ    
  3255тЖТ    // Send alerts
  3256тЖТ    if (alerts.length > 0) {
  3257тЖТ      await this.sendDriftAlerts(alerts);
  3258тЖТ    }
  3259тЖТ    
  3260тЖТ    // Broadcast to canvas
  3261тЖТ    await this.websocketHub.broadcast('drift:updated', {
  3262тЖТ      baselineId: baseline.id,
  3263тЖТ      analysisDate,
  3264тЖТ      summary: {
  3265тЖТ        totalTrains: trains.length,
  3266тЖТ        trainsWithDrift: trainAnalyses.filter(a => Math.abs(a.mileageDriftPct) > 1).length,
  3267тЖТ        trainsRequiringReplan,
  3268тЖТ        avgFleetDriftPct: trainAnalyses.reduce((sum, a) => sum + a.mileageDriftPct, 0) / trainAnalyses.length
  3269тЖТ      },
  3270тЖТ      alerts
  3271тЖТ    });
  3272тЖТ    
  3273тЖТ    return {
  3274тЖТ      skipped: false,
  3275тЖТ      baselineId: baseline.id,
  3276тЖТ      analysisDate,
  3277тЖТ      trainAnalyses,
  3278тЖТ      alerts
  3279тЖТ    };
  3280тЖТ  }
  3281тЖТ  
  3282тЖТ  private async analyzeTrainDrift(
  3283тЖТ    train: Train,
  3284тЖТ    baseline: PlanBaseline,
  3285тЖТ    analysisDate: Date
  3286тЖТ  ): Promise<TrainDriftAnalysis> {
  3287тЖТ    // Get baseline projection for today
  3288тЖТ    const baselineProjection = await this.db.query.baselineMileageProjection.findFirst({
  3289тЖТ      where: and(
  3290тЖТ        eq(baselineMileageProjection.baselineId, baseline.id),
  3291тЖТ        eq(baselineMileageProjection.trainId, train.id),
  3292тЖТ        lte(baselineMileageProjection.projectionDate, analysisDate)
  3293тЖТ      ),
  3294тЖТ      orderBy: desc(baselineMileageProjection.projectionDate)
  3295тЖТ    });
  3296тЖТ    
  3297тЖТ    // Calculate mileage drift
  3298тЖТ    const baselineKm = baselineProjection?.projectedCumulativeKm || train.currentMileageKm;
  3299тЖТ    const actualKm = train.currentMileageKm;
  3300тЖТ    const mileageDriftKm = actualKm - baselineKm;
  3301тЖТ    const mileageDriftPct = (mileageDriftKm / baselineKm) * 100;
  3302тЖТ    
  3303тЖТ    // Get baseline PM schedule
  3304тЖТ    const baselinePMs = await this.db.query.baselinePmSchedule.findMany({
  3305тЖТ      where: and(
  3306тЖТ        eq(baselinePmSchedule.baselineId, baseline.id),
  3307тЖТ        eq(baselinePmSchedule.trainId, train.id),
  3308тЖТ        gte(baselinePmSchedule.projectedDate, analysisDate)
  3309тЖТ      )
  3310тЖТ    });
  3311тЖТ    
  3312тЖТ    // Get current PM schedule
  3313тЖТ    const currentPMs = await this.db.query.pmSchedule.findMany({
  3314тЖТ      where: and(
  3315тЖТ        eq(pmSchedule.trainId, train.id),
  3316тЖТ        isNull(pmSchedule.scenarioId),
  3317тЖТ        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
  3318тЖТ        gte(pmSchedule.targetDate, analysisDate)
  3319тЖТ      )
  3320тЖТ    });
  3321тЖТ    
  3322тЖТ    // Calculate PM drift
  3323тЖТ    const pmDrifts: PMDrift[] = [];
  3324тЖТ    
  3325тЖТ    for (const baselinePM of baselinePMs) {
  3326тЖТ      const currentPM = currentPMs.find(
  3327тЖТ        p => p.pmTypeId === baselinePM.pmTypeId
  3328тЖТ      );
  3329тЖТ      
  3330тЖТ      if (currentPM) {
  3331тЖТ        const driftDays = differenceInDays(
  3332тЖТ          new Date(currentPM.targetDate),
  3333тЖТ          new Date(baselinePM.projectedDate)
  3334тЖТ        );
  3335тЖТ        
  3336тЖТ        pmDrifts.push({
  3337тЖТ          pmTypeId: baselinePM.pmTypeId,
  3338тЖТ          baselineDate: baselinePM.projectedDate,
  3339тЖТ          currentDate: currentPM.targetDate,
  3340тЖТ          driftDays,
  3341тЖТ          direction: driftDays > 0 ? 'LATER' : driftDays < 0 ? 'EARLIER' : 'ON_TRACK'
  3342тЖТ        });
  3343тЖТ      }
  3344тЖТ    }
  3345тЖТ    
  3346тЖТ    const avgPmDriftDays = pmDrifts.length > 0
  3347тЖТ      ? pmDrifts.reduce((sum, p) => sum + Math.abs(p.driftDays), 0) / pmDrifts.length
  3348тЖТ      : 0;
  3349тЖТ    
  3350тЖТ    const maxPmDriftDays = pmDrifts.length > 0
  3351тЖТ      ? Math.max(...pmDrifts.map(p => Math.abs(p.driftDays)))
  3352тЖТ      : 0;
  3353тЖТ    
  3354тЖТ    // Determine if replan required
  3355тЖТ    const requiresReplan = 
  3356тЖТ      Math.abs(mileageDriftPct) > this.thresholds.mileageDriftPct ||
  3357тЖТ      maxPmDriftDays > this.thresholds.scheduleDriftDays;
  3358тЖТ    
  3359тЖТ    let replanReason: string | undefined;
  3360тЖТ    if (requiresReplan) {
  3361тЖТ      const reasons: string[] = [];
  3362тЖТ      if (Math.abs(mileageDriftPct) > this.thresholds.mileageDriftPct) {
  3363тЖТ        reasons.push(`Mileage drift ${mileageDriftPct.toFixed(1)}% exceeds ${this.thresholds.mileageDriftPct}% threshold`);
  3364тЖТ      }
  3365тЖТ      if (maxPmDriftDays > this.thresholds.scheduleDriftDays) {
  3366тЖТ        reasons.push(`PM schedule drift ${maxPmDriftDays} days exceeds ${this.thresholds.scheduleDriftDays} day threshold`);
  3367тЖТ      }
  3368тЖТ      replanReason = reasons.join('; ');
  3369тЖТ    }
  3370тЖТ    
  3371тЖТ    return {
  3372тЖТ      trainId: train.id,
  3373тЖТ      trainNumber: train.trainNumber,
  3374тЖТ      baselineProjectedKm: baselineKm,
  3375тЖТ      actualKm,
  3376тЖТ      mileageDriftKm,
  3377тЖТ      mileageDriftPct,
  3378тЖТ      pmDrifts,
  3379тЖТ      avgPmDriftDays,
  3380тЖТ      maxPmDriftDays,
  3381тЖТ      requiresReplan,
  3382тЖТ      replanReason
  3383тЖТ    };
  3384тЖТ  }
  3385тЖТ}
  3386тЖТ```
  3387тЖТ
