  3390тЖТ## 4.9 Simulation Engine
  3391тЖТ
  3392тЖТ### 4.9.1 Purpose
  3393тЖТ
  3394тЖТEnable what-if scenario analysis with persistent storage and comparison capabilities.
  3395тЖТ
  3396тЖТ### 4.9.2 Implementation
  3397тЖТ
  3398тЖТ```typescript
  3399тЖТclass SimulationEngine {
  3400тЖТ  /**
  3401тЖТ   * Create a new scenario branched from baseline or another scenario
  3402тЖТ   */
  3403тЖТ  async createScenario(
  3404тЖТ    name: string,
  3405тЖТ    description: string,
  3406тЖТ    forkFrom: { type: 'BASELINE' | 'SCENARIO'; id: string },
  3407тЖТ    userId: string
  3408тЖТ  ): Promise<Scenario> {
  3409тЖТ    const scenario = await this.db.insert(scenarios)
  3410тЖТ      .values({
  3411тЖТ        name,
  3412тЖТ        description,
  3413тЖТ        forkedFromBaselineId: forkFrom.type === 'BASELINE' ? forkFrom.id : null,
  3414тЖТ        forkedFromScenarioId: forkFrom.type === 'SCENARIO' ? forkFrom.id : null,
  3415тЖТ        status: 'ACTIVE',
  3416тЖТ        createdBy: userId,
  3417тЖТ        expiresAt: addDays(new Date(), 30)
  3418тЖТ      })
  3419тЖТ      .returning();
  3420тЖТ    
  3421тЖТ    return scenario[0];
  3422тЖТ  }
  3423тЖТ  
  3424тЖТ  /**
  3425тЖТ   * Apply a change to a scenario (event-sourced)
  3426тЖТ   */
  3427тЖТ  async applyChange(
  3428тЖТ    scenarioId: string,
  3429тЖТ    change: ScenarioChange,
  3430тЖТ    userId: string
  3431тЖТ  ): Promise<void> {
  3432тЖТ    // Get next sequence number
  3433тЖТ    const lastDelta = await this.db.query.scenarioDeltas.findFirst({
  3434тЖТ      where: eq(scenarioDeltas.scenarioId, scenarioId),
  3435тЖТ      orderBy: desc(scenarioDeltas.sequenceNum)
  3436тЖТ    });
  3437тЖТ    
  3438тЖТ    const sequenceNum = (lastDelta?.sequenceNum || 0) + 1;
  3439тЖТ    
  3440тЖТ    // Record delta
  3441тЖТ    await this.db.insert(scenarioDeltas)
  3442тЖТ      .values({
  3443тЖТ        scenarioId,
  3444тЖТ        sequenceNum,
  3445тЖТ        deltaType: change.type,
  3446тЖТ        entityType: change.entityType,
  3447тЖТ        entityId: change.entityId,
  3448тЖТ        oldValues: change.oldValues,
  3449тЖТ        newValues: change.newValues,
  3450тЖТ        changeReason: change.reason,
  3451тЖТ        createdBy: userId
  3452тЖТ      });
  3453тЖТ    
  3454тЖТ    // Update scenario timestamp
  3455тЖТ    await this.db.update(scenarios)
  3456тЖТ      .set({
  3457тЖТ        lastModifiedAt: new Date(),
  3458тЖТ        expiresAt: addDays(new Date(), 30)  // Reset expiration
  3459тЖТ      })
  3460тЖТ      .where(eq(scenarios.id, scenarioId));
  3461тЖТ  }
  3462тЖТ  
  3463тЖТ  /**
  3464тЖТ   * Materialize a scenario (apply all deltas to get full state)
  3465тЖТ   */
  3466тЖТ  async materializeScenario(scenarioId: string): Promise<MaterializedScenario> {
  3467тЖТ    const scenario = await this.db.query.scenarios.findFirst({
  3468тЖТ      where: eq(scenarios.id, scenarioId)
  3469тЖТ    });
  3470тЖТ    
  3471тЖТ    if (!scenario) {
  3472тЖТ      throw new NotFoundError('Scenario not found');
  3473тЖТ    }
  3474тЖТ    
  3475тЖТ    // Get base state
  3476тЖТ    let basePMSchedule: PMScheduleRecord[];
  3477тЖТ    
  3478тЖТ    if (scenario.forkedFromBaselineId) {
  3479тЖТ      basePMSchedule = await this.db.query.baselinePmSchedule.findMany({
  3480тЖТ        where: eq(baselinePmSchedule.baselineId, scenario.forkedFromBaselineId)
  3481тЖТ      });
  3482тЖТ    } else if (scenario.forkedFromScenarioId) {
  3483тЖТ      // Recursive materialization
  3484тЖТ      const parentScenario = await this.materializeScenario(scenario.forkedFromScenarioId);
  3485тЖТ      basePMSchedule = parentScenario.pmSchedule;
  3486тЖТ    } else {
  3487тЖТ      // Fork from current production
  3488тЖТ      basePMSchedule = await this.db.query.pmSchedule.findMany({
  3489тЖТ        where: isNull(pmSchedule.scenarioId)
  3490тЖТ      });
  3491тЖТ    }
  3492тЖТ    
  3493тЖТ    // Get all deltas in order
  3494тЖТ    const deltas = await this.db.query.scenarioDeltas.findMany({
  3495тЖТ      where: eq(scenarioDeltas.scenarioId, scenarioId),
  3496тЖТ      orderBy: asc(scenarioDeltas.sequenceNum)
  3497тЖТ    });
  3498тЖТ    
  3499тЖТ    // Apply deltas
  3500тЖТ    const materializedPMSchedule = [...basePMSchedule];
  3501тЖТ    
  3502тЖТ    for (const delta of deltas) {
  3503тЖТ      switch (delta.deltaType) {
  3504тЖТ        case 'PM_MOVE': {
  3505тЖТ          const idx = materializedPMSchedule.findIndex(
  3506тЖТ            pm => pm.id === delta.entityId
  3507тЖТ          );
  3508тЖТ          if (idx >= 0) {
  3509тЖТ            materializedPMSchedule[idx] = {
  3510тЖТ              ...materializedPMSchedule[idx],
  3511тЖТ              ...delta.newValues
  3512тЖТ            };
  3513тЖТ          }
  3514тЖТ          break;
  3515тЖТ        }
  3516тЖТ        case 'PM_ADD': {
  3517тЖТ          materializedPMSchedule.push({
  3518тЖТ            id: delta.entityId,
  3519тЖТ            ...delta.newValues
  3520тЖТ          });
  3521тЖТ          break;
  3522тЖТ        }
  3523тЖТ        case 'PM_REMOVE': {
  3524тЖТ          const idx = materializedPMSchedule.findIndex(
  3525тЖТ            pm => pm.id === delta.entityId
  3526тЖТ          );
  3527тЖТ          if (idx >= 0) {
  3528тЖТ            materializedPMSchedule.splice(idx, 1);
  3529тЖТ          }
  3530тЖТ          break;
  3531тЖТ        }
  3532тЖТ      }
  3533тЖТ    }
  3534тЖТ    
  3535тЖТ    return {
  3536тЖТ      scenario,
  3537тЖТ      pmSchedule: materializedPMSchedule,
  3538тЖТ      deltasApplied: deltas.length
  3539тЖТ    };
  3540тЖТ  }
  3541тЖТ  
  3542тЖТ  /**
  3543тЖТ   * Compare two scenarios or scenario vs baseline
  3544тЖТ   */
  3545тЖТ  async compareScenarios(
  3546тЖТ    scenarioAId: string,
  3547тЖТ    scenarioBId: string | null,  // null = compare to published baseline
  3548тЖТ    baselineId?: string
  3549тЖТ  ): Promise<ScenarioComparison> {
  3550тЖТ    // Materialize both
  3551тЖТ    const scenarioA = await this.materializeScenario(scenarioAId);
  3552тЖТ    
  3553тЖТ    let scenarioB: MaterializedScenario;
  3554тЖТ    if (scenarioBId) {
  3555тЖТ      scenarioB = await this.materializeScenario(scenarioBId);
  3556тЖТ    } else {
  3557тЖТ      // Use baseline
  3558тЖТ      const baseline = baselineId 
  3559тЖТ        ? await this.db.query.planBaselines.findFirst({
  3560тЖТ            where: eq(planBaselines.id, baselineId)
  3561тЖТ          })
  3562тЖТ        : await this.getPublishedBaseline();
  3563тЖТ      
  3564тЖТ      if (!baseline) {
  3565тЖТ        throw new NotFoundError('No baseline for comparison');
  3566тЖТ      }
  3567тЖТ      
  3568тЖТ      const baselinePMs = await this.db.query.baselinePmSchedule.findMany({
  3569тЖТ        where: eq(baselinePmSchedule.baselineId, baseline.id)
  3570тЖТ      });
  3571тЖТ      
  3572тЖТ      scenarioB = {
  3573тЖТ        scenario: null,
  3574тЖТ        pmSchedule: baselinePMs,
  3575тЖТ        deltasApplied: 0
  3576тЖТ      };
  3577тЖТ    }
  3578тЖТ    
  3579тЖТ    // Calculate differences
  3580тЖТ    const pmDifferences = this.calculatePMDifferences(
  3581тЖТ      scenarioA.pmSchedule,
  3582тЖТ      scenarioB.pmSchedule
  3583тЖТ    );
  3584тЖТ    
  3585тЖТ    const manhourDifferences = await this.calculateManhourDifferences(
  3586тЖТ      scenarioA.pmSchedule,
  3587тЖТ      scenarioB.pmSchedule
  3588тЖТ    );
  3589тЖТ    
  3590тЖТ    const costDifferences = await this.calculateCostDifferences(
  3591тЖТ      scenarioA.pmSchedule,
  3592тЖТ      scenarioB.pmSchedule
  3593тЖТ    );
  3594тЖТ    
  3595тЖТ    // Persist comparison
  3596тЖТ    const comparison = await this.db.insert(scenarioComparisons)
  3597тЖТ      .values({
  3598тЖТ        scenarioAId,
  3599тЖТ        scenarioBId,
  3600тЖТ        baselineId: scenarioBId ? null : (baselineId || await this.getPublishedBaselineId()),
  3601тЖТ        comparisonDate: new Date(),
  3602тЖТ        pmCountDelta: pmDifferences.countDelta,
  3603тЖТ        totalHoursDelta: manhourDifferences.totalDelta,
  3604тЖТ        totalCostDelta: costDifferences.totalDelta,
  3605тЖТ        overloadedWeeksDelta: manhourDifferences.overloadedWeeksDelta,
  3606тЖТ        pmDifferences: pmDifferences.details,
  3607тЖТ        manhourDifferences: manhourDifferences.details
  3608тЖТ      })
  3609тЖТ      .returning();
  3610тЖТ    
  3611тЖТ    return {
  3612тЖТ      ...comparison[0],
  3613тЖТ      pmDifferences,
  3614тЖТ      manhourDifferences,
  3615тЖТ      costDifferences
  3616тЖТ    };
  3617тЖТ  }
  3618тЖТ  
  3619тЖТ  /**
  3620тЖТ   * Promote a scenario to become the new baseline
  3621тЖТ   */
  3622тЖТ  async promoteToBaseline(
  3623тЖТ    scenarioId: string,
  3624тЖТ    baselineName: string,
  3625тЖТ    userId: string
  3626тЖТ  ): Promise<PlanBaseline> {
  3627тЖТ    const materialized = await this.materializeScenario(scenarioId);
