  3635тЖТ    
  3636тЖТ    // Apply scenario deltas to production PM schedule
  3637тЖТ    await this.db.transaction(async (tx) => {
  3638тЖТ      for (const pm of materialized.pmSchedule) {
  3639тЖТ        await tx.insert(pmSchedule)
  3640тЖТ          .values({
  3641тЖТ            ...pm,
