  3672тЖТ
  3673тЖТ## 4.10 Costing Service
  3674тЖТ
  3675тЖТ### 4.10.1 Purpose
  3676тЖТ
  3677тЖТCalculate TCO projections, track variance against budget, and provide cost impact analysis for adjustments.
  3678тЖТ
  3679тЖТ### 4.10.2 Implementation
  3680тЖТ
  3681тЖТ```typescript
  3682тЖТinterface CostBreakdown {
  3683тЖТ  laborCost: number;
  3684тЖТ  overtimeCost: number;
  3685тЖТ  materialCost: number;
  3686тЖТ  contractorCost: number;
  3687тЖТ  overheadCost: number;
  3688тЖТ  totalCost: number;
  3689тЖТ}
  3690тЖТ
  3691тЖТclass CostingService {
  3692тЖТ  async calculatePMCost(
  3693тЖТ    pmScheduleId: string,
  3694тЖТ    includeProjected: boolean = false
  3695тЖТ  ): Promise<CostBreakdown> {
  3696тЖТ    const pm = await this.db.query.pmSchedule.findFirst({
  3697тЖТ      where: eq(pmSchedule.id, pmScheduleId),
  3698тЖТ      with: {
  3699тЖТ        pmType: true,
  3700тЖТ        assignedDepot: true
  3701тЖТ      }
  3702тЖТ    });
  3703тЖТ    
  3704тЖТ    if (!pm) {
  3705тЖТ      throw new NotFoundError('PM not found');
  3706тЖТ    }
  3707тЖТ    
  3708тЖТ    // Get labor rates
  3709тЖТ    const laborRate = await this.getLaborRate(pm.assignedDepotId, pm.targetDate);
  3710тЖТ    
  3711тЖТ    // Get material costs
  3712тЖТ    const materialCost = await this.calculateMaterialCost(pm.pmType.id);
  3713тЖТ    
  3714тЖТ    // Calculate labor cost
  3715тЖТ    const hours = pm.actualHours || pm.assignedHours || pm.pmType.estimatedHours;
  3716тЖТ    const laborCost = hours * laborRate.shopRateHourly;
  3717тЖТ    
  3718тЖТ    // Overtime (if applicable)
  3719тЖТ    let overtimeCost = 0;
  3720тЖТ    if (pm.assignedShift === 'NIGHT' || pm.assignedShift === 'WEEKEND') {
  3721тЖТ      const multiplier = pm.assignedShift === 'WEEKEND' 
  3722тЖТ        ? laborRate.weekendMultiplier 
  3723тЖТ        : laborRate.overtimeMultiplier;
  3724тЖТ      overtimeCost = hours * laborRate.regularHourlyRate * (multiplier - 1);
  3725тЖТ    }
  3726тЖТ    
  3727тЖТ    // Overhead (typically 15-20% of direct costs)
  3728тЖТ    const overheadRate = 0.18;
  3729тЖТ    const directCost = laborCost + materialCost;
  3730тЖТ    const overheadCost = directCost * overheadRate;
  3731тЖТ    
  3732тЖТ    return {
  3733тЖТ      laborCost,
  3734тЖТ      overtimeCost,
  3735тЖТ      materialCost,
  3736тЖТ      contractorCost: 0,
  3737тЖТ      overheadCost,
  3738тЖТ      totalCost: laborCost + overtimeCost + materialCost + overheadCost
  3739тЖТ    };
  3740тЖТ  }
  3741тЖТ  
  3742тЖТ  async projectTCO(
  3743тЖТ    horizonYears: number = 12
  3744тЖТ  ): Promise<TCOProjection> {
  3745тЖТ    const projections: YearlyCost[] = [];
  3746тЖТ    const startYear = new Date().getFullYear();
  3747тЖТ    
  3748тЖТ    for (let year = 0; year < horizonYears; year++) {
  3749тЖТ      const fiscalYear = startYear + year;
  3750тЖТ      
  3751тЖТ      // Get scheduled PMs for this year
  3752тЖТ      const yearStart = new Date(fiscalYear, 0, 1);
  3753тЖТ      const yearEnd = new Date(fiscalYear, 11, 31);
  3754тЖТ      
  3755тЖТ      const scheduledPMs = await this.db.query.pmSchedule.findMany({
  3756тЖТ        where: and(
  3757тЖТ          isNull(pmSchedule.scenarioId),
  3758тЖТ          gte(pmSchedule.targetDate, yearStart),
  3759тЖТ          lte(pmSchedule.targetDate, yearEnd)
  3760тЖТ        ),
  3761тЖТ        with: { pmType: true }
  3762тЖТ      });
  3763тЖТ      
  3764тЖТ      // Calculate costs
  3765тЖТ      let totalLabor = 0;
  3766тЖТ      let totalMaterial = 0;
  3767тЖТ      
  3768тЖТ      for (const pm of scheduledPMs) {
  3769тЖТ        const cost = await this.calculatePMCost(pm.id, true);
  3770тЖТ        totalLabor += cost.laborCost + cost.overtimeCost;
  3771тЖТ        totalMaterial += cost.materialCost;
  3772тЖТ      }
  3773тЖТ      
  3774тЖТ      // Apply inflation adjustment for future years
  3775тЖТ      const inflationRate = 0.03;
  3776тЖТ      const inflationFactor = Math.pow(1 + inflationRate, year);
  3777тЖТ      
  3778тЖТ      projections.push({
  3779тЖТ        fiscalYear,
  3780тЖТ        laborCost: totalLabor * inflationFactor,
  3781тЖТ        materialCost: totalMaterial * inflationFactor,
  3782тЖТ        pmCount: scheduledPMs.length,
  3783тЖТ        inflationFactor
  3784тЖТ      });
  3785тЖТ    }
  3786тЖТ    
  3787тЖТ    // Calculate NPV
  3788тЖТ    const discountRate = 0.05;
  3789тЖТ    let npv = 0;
  3790тЖТ    
  3791тЖТ    for (let i = 0; i < projections.length; i++) {
  3792тЖТ      const yearCost = projections[i].laborCost + projections[i].materialCost;
  3793тЖТ      npv += yearCost / Math.pow(1 + discountRate, i);
  3794тЖТ    }
  3795тЖТ    
  3796тЖТ    return {
  3797тЖТ      projections,
  3798тЖТ      summary: {
  3799тЖТ        totalLaborCost: projections.reduce((sum, p) => sum + p.laborCost, 0),
  3800тЖТ        totalMaterialCost: projections.reduce((sum, p) => sum + p.materialCost, 0),
  3801тЖТ        totalPMCount: projections.reduce((sum, p) => sum + p.pmCount, 0),
  3802тЖТ        npv,
  3803тЖТ        avgAnnualCost: npv / horizonYears
  3804тЖТ      }
  3805тЖТ    };
  3806тЖТ  }
  3807тЖТ  
  3808тЖТ  async calculateVariance(
  3809тЖТ    fiscalYear: number,
  3810тЖТ    depotId?: string
  3811тЖТ  ): Promise<CostVariance> {
  3812тЖТ    const baseline = await this.db.query.costBaselines.findFirst({
  3813тЖТ      where: and(
  3814тЖТ        eq(costBaselines.fiscalYear, fiscalYear),
  3815тЖТ        depotId ? eq(costBaselines.depotId, depotId) : isNull(costBaselines.depotId)
  3816тЖТ      )
  3817тЖТ    });
  3818тЖТ    
  3819тЖТ    if (!baseline) {
  3820тЖТ      throw new NotFoundError('Cost baseline not found');
  3821тЖТ    }
  3822тЖТ    
  3823тЖТ    // Get actual costs from completed PMs
  3824тЖТ    const yearStart = new Date(fiscalYear, 0, 1);
  3825тЖТ    const yearEnd = new Date(fiscalYear, 11, 31);
  3826тЖТ    
  3827тЖТ    const completedPMs = await this.db.query.pmSchedule.findMany({
  3828тЖТ      where: and(
  3829тЖТ        eq(pmSchedule.status, 'COMPLETED'),
  3830тЖТ        gte(pmSchedule.completedAt, yearStart),
  3831тЖТ        lte(pmSchedule.completedAt, yearEnd),
  3832тЖТ        depotId ? eq(pmSchedule.assignedDepotId, depotId) : undefined
  3833тЖТ      )
  3834тЖТ    });
  3835тЖТ    
  3836тЖТ    let actualLaborCost = 0;
  3837тЖТ    let actualMaterialCost = 0;
  3838тЖТ    
  3839тЖТ    for (const pm of completedPMs) {
  3840тЖТ      const cost = await this.calculatePMCost(pm.id);
  3841тЖТ      actualLaborCost += cost.laborCost + cost.overtimeCost;
  3842тЖТ      actualMaterialCost += cost.materialCost;
  3843тЖТ    }
  3844тЖТ    
  3845тЖТ    const actualTotal = actualLaborCost + actualMaterialCost;
  3846тЖТ    const budgetTotal = baseline.budgetTotal;
  3847тЖТ    
  3848тЖТ    return {
  3849тЖТ      fiscalYear,
  3850тЖТ      depotId,
  3851тЖТ      budget: {
  3852тЖТ        labor: baseline.budgetLaborCost,
  3853тЖТ        material: baseline.budgetMaterialCost,
  3854тЖТ        total: budgetTotal
  3855тЖТ      },
  3856тЖТ      actual: {
  3857тЖТ        labor: actualLaborCost,
  3858тЖТ        material: actualMaterialCost,
  3859тЖТ        total: actualTotal
  3860тЖТ      },
  3861тЖТ      variance: {
  3862тЖТ        labor: actualLaborCost - baseline.budgetLaborCost,
  3863тЖТ        material: actualMaterialCost - baseline.budgetMaterialCost,
  3864тЖТ        total: actualTotal - budgetTotal,
  3865тЖТ        percentage: ((actualTotal - budgetTotal) / budgetTotal) * 100
  3866тЖТ      },
  3867тЖТ      status: actualTotal <= budgetTotal ? 'UNDER_BUDGET' : 
  3868тЖТ              actualTotal <= budgetTotal * 1.1 ? 'WITHIN_TOLERANCE' : 'OVER_BUDGET'
  3869тЖТ    };
  3870тЖТ  }
  3871тЖТ}
